import React, { useState, useEffect } from 'react';
// Função utilitária para buscar municípios do arquivo JSON
async function fetchMunicipios() {
  try {
    const resp = await fetch('/municipiosIBGE.json');
    if (!resp.ok) return [];
    const data = await resp.json();
    return data;
  } catch {
    return [];
  }
}

const campos = [
  'Ano',
  'Nome da Estação',
  'Número da estação',
  'Latitude',
  'Longitude',
  'UF',
  'Município',
  'Longitude',
  'Status',
  'Data de Ativação',
  'Data de Desativação',
  'Responsável Técnico',
  'Contato',
  'Observações'
];

export default function EstacoesInfra() {
  const [valores, setValores] = useState(Array(campos.length).fill(''));
  const [municipios, setMunicipios] = useState([]);

  useEffect(() => {
    fetchMunicipios().then(setMunicipios);
  }, []);

  const handleChange = (idx, value) => {
    setValores(v => {
      const novo = [...v];
      novo[idx] = value;
      return novo;
    });
  };

  const handleSubmit = e => {
    e.preventDefault();
    alert('Dados enviados!');
    // Aqui você pode enviar os dados para o backend
  };

  return (
    <form onSubmit={handleSubmit} style={{maxWidth:500, margin:'0 auto', background:'#fff', padding:24, borderRadius:8, boxShadow:'0 2px 8px #0001'}}>
      <h2 style={{marginBottom:24}}>Cadastro de Estações</h2>
      {campos.map((campo, idx) => (
        <div key={campo} style={{marginBottom:16}}>
          <label style={{
            display:'block',
            fontWeight: (idx === 0 || campo === 'Nome da Estação' || campo === 'Número da estação' || campo === 'Latitude' || campo === 'Longitude' || campo === 'UF' || campo === 'Município') ? 700 : 500,
            marginBottom:4,
            color: idx === 0 ? '#111' : undefined
          }}>{campo}</label>
          {idx === 0 ? (
            <select
              value={valores[0]}
              onChange={e => handleChange(0, e.target.value)}
              style={{
                width:'100%',
                padding:8,
                borderRadius:4,
                border:'1px solid #ccc',
                fontWeight:400,
                fontSize:16,
                background:'#f3f6fa',
                color:'#222',
                boxShadow:'none',
                letterSpacing:0
              }}
            >
              <option value="">Selecione o ano</option>
              <option value="2024">2024</option>
              <option value="2025">2025</option>
              <option value="2026">2026</option>
            </select>
          ) : campo === 'UF' ? (
            <select
              value={valores[idx]}
              onChange={e => handleChange(idx, e.target.value)}
              style={{
                width:'100%',
                padding:8,
                borderRadius:4,
                border:'1px solid #ccc',
                fontWeight:400,
                fontSize:15,
                background:'#fff',
                color:'#222'
              }}
            >
              <option value="">Selecione o estado</option>
              <option value="AC">Acre (AC)</option>
              <option value="AL">Alagoas (AL)</option>
              <option value="AP">Amapá (AP)</option>
              <option value="AM">Amazonas (AM)</option>
              <option value="BA">Bahia (BA)</option>
              <option value="CE">Ceará (CE)</option>
              <option value="DF">Distrito Federal (DF)</option>
              <option value="ES">Espírito Santo (ES)</option>
              <option value="GO">Goiás (GO)</option>
              <option value="MA">Maranhão (MA)</option>
              <option value="MT">Mato Grosso (MT)</option>
              <option value="MS">Mato Grosso do Sul (MS)</option>
              <option value="MG">Minas Gerais (MG)</option>
              <option value="PA">Pará (PA)</option>
              <option value="PB">Paraíba (PB)</option>
              <option value="PR">Paraná (PR)</option>
              <option value="PE">Pernambuco (PE)</option>
              <option value="PI">Piauí (PI)</option>
              <option value="RJ">Rio de Janeiro (RJ)</option>
              <option value="RN">Rio Grande do Norte (RN)</option>
              <option value="RS">Rio Grande do Sul (RS)</option>
              <option value="RO">Rondônia (RO)</option>
              <option value="RR">Roraima (RR)</option>
              <option value="SC">Santa Catarina (SC)</option>
              <option value="SP">São Paulo (SP)</option>
              <option value="SE">Sergipe (SE)</option>
              <option value="TO">Tocantins (TO)</option>
            </select>
          ) : campo === 'Município' ? (
            <select
              value={valores[idx]}
              onChange={e => handleChange(idx, e.target.value)}
              style={{
                width:'100%',
                padding:8,
                borderRadius:4,
                border:'1px solid #ccc',
                fontWeight:400,
                fontSize:15,
                background:'#fff',
                color:'#222'
              }}
            >
              <option value="">Selecione o município</option>
              {municipios.map(m => (
                <option key={m.codigo_ibge || m.nome} value={m.codigo_ibge}>{m.nome}</option>
              ))}
            </select>
          ) : (
            <input
              type="text"
              value={valores[idx]}
              onChange={e => handleChange(idx, e.target.value)}
              placeholder={campo === 'Nome da Estação' ? 'Nome que você dá a sua estação' : campo === 'Número da estação' ? 'Número da estação no sistema da Anatel.' : campo === 'Latitude' && idx === 3 ? 'Latitude em graus decimais. Ex.: -23,5505' : campo === 'Longitude' && idx === 4 ? 'Longitude em graus decimais. Ex.: -46,6333' : ''}
              style={{
                width:'100%',
                padding:8,
                borderRadius:4,
                border:'1px solid #ccc',
                fontWeight:400,
                fontSize:15,
                background:'#fff',
                color:'#222',
                fontStyle: ((campo === 'Nome da Estação' || campo === 'Número da estação' || (campo === 'Latitude' && idx === 3) || (campo === 'Longitude' && idx === 4)) && !valores[idx]) ? 'italic' : 'normal'
              }}
            />
          )}
        </div>
      ))}
      <button type="submit" style={{marginTop:16, padding:'10px 24px', background:'#1976d2', color:'#fff', border:'none', borderRadius:4, fontWeight:600, fontSize:16, cursor:'pointer'}}>Salvar</button>
    </form>
  );
}
